// GOLD PRICE
function updateGoldDisplay(priceUSD, changePct) {
  const priceEl = document.getElementById('hero-gold-price');
  const changeEl = document.getElementById('hero-gold-change');
  if (priceEl && priceUSD) {
    priceEl.textContent = '$' + parseFloat(priceUSD).toLocaleString('en-US', { maximumFractionDigits: 0 });
  }
  if (changeEl) {
    if (changePct !== null && changePct !== undefined) {
      const pct = parseFloat(changePct);
      const isUp = pct >= 0;
      changeEl.textContent = (isUp ? '▲ +' : '▼ ') + Math.abs(pct).toFixed(2) + '%';
      changeEl.className = 'hpc-change ' + (isUp ? 'up' : 'down');
    } else {
      changeEl.textContent = '--';
      changeEl.className = 'hpc-change';
    }
  }
}

async function fetchGoldPrice() {
  // Primary: goldprice.org public endpoint (no CORS issues)
  try {
    const res = await fetch('https://data-asg.goldprice.org/dbXRates/USD', {
      headers: { 'Accept': 'application/json' }
    });
    if (!res.ok) throw new Error('goldprice.org non-200');
    const data = await res.json();
    const item = Array.isArray(data.items) ? data.items[0] : null;
    const price = item && item.xauPrice ? item.xauPrice : null;
    const chg = item && item.chgXau != null ? item.chgXau : null;
    if (price) {
      updateGoldDisplay(price, chg);
      return;
    }
    throw new Error('goldprice.org: no xauPrice');
  } catch(e) {
    console.log('Gold primary failed, trying PAXG fallback:', e.message);
  }

  // Fallback: CoinGecko PAXG (PAX Gold token ≈ 1 troy oz gold)
  try {
    const res = await fetch(
      'https://api.coingecko.com/api/v3/simple/price?ids=pax-gold&vs_currencies=usd&include_24hr_change=true'
    );
    if (!res.ok) throw new Error('CoinGecko PAXG non-200');
    const data = await res.json();
    const price = data['pax-gold'] && data['pax-gold'].usd ? data['pax-gold'].usd : null;
    const chg = data['pax-gold'] && data['pax-gold'].usd_24h_change != null
      ? data['pax-gold'].usd_24h_change : null;
    if (price) {
      updateGoldDisplay(price, chg);
      return;
    }
    throw new Error('PAXG: no price');
  } catch(e) {
    const el = document.getElementById('hero-gold-price');
    if (el) el.textContent = '--';
    console.log('Gold fallback also failed:', e.message);
  }
}
