// handleModalSubmit — validates form then saves to Supabase
async function handleModalSubmit() {
  const name      = document.getElementById('m-inp-name');
  const phone     = document.getElementById('m-inp-phone');
  const capital   = document.getElementById('m-inp-capital');
  const goalGroup = document.getElementById('m-inp-goal-group');
  const telegram  = document.getElementById('m-inp-telegram');
  const province  = document.getElementById('m-inp-province');

  function shakeField(el) {
    if (!el) return;
    el.style.borderColor = 'rgba(248,113,113,0.75)';
    el.style.boxShadow = '0 0 0 3px rgba(248,113,113,0.15)';
    el.focus();
    setTimeout(() => { el.style.borderColor = ''; el.style.boxShadow = ''; }, 2200);
  }

  if (!name || !name.value.trim())   { shakeField(name);  return; }
  if (!phone || !phone.value.trim()) { shakeField(phone); return; }
  if (!capital || !capital.value)    { shakeField(capital); return; }
  if (goalGroup && !goalGroup.querySelector('.pill-chip.active')) {
    goalGroup.style.outline = '1.5px solid rgba(248,113,113,0.5)';
    goalGroup.style.borderRadius = '8px';
    setTimeout(() => { goalGroup.style.outline = ''; }, 2200);
    return;
  }

  // Disable button while submitting
  const btn  = document.querySelector('#register-modal .submit-btn');
  const span = btn && btn.querySelector('span');
  if (btn) btn.disabled = true;
  if (span) span.textContent = 'Đang gửi...';

  // Save to Supabase
  const { error } = await _supabase.from('Registration').insert([{
    ho_ten:          name.value.trim(),
    zalo:            phone.value.trim(),
    telegram:        telegram?.value.trim() || null,
    tinh_thanh_pho:  province?.value || null,
    von:             capital?.value || null,
    muc_tieu:        getSelectedGoals() || null
  }]);

  if (error) {
    // Show error state
    console.error('Supabase error:', JSON.stringify(error));
    if (span) span.textContent = '⚠ Lỗi — thử lại sau';
    if (btn)  { btn.style.background = 'rgba(248,113,113,0.3)'; btn.disabled = false; }
    setTimeout(() => {
      if (btn)  btn.style.background = '';
      if (span) span.textContent = 'Gửi Đơn Đăng Ký';
    }, 3000);
    return;
  }

  // Success
  if (span) span.textContent = '✓ Đã Gửi Thành Công!';
  if (btn)  btn.style.background = 'linear-gradient(135deg,#059669,#34D399)';
  setTimeout(() => {
    if (btn)  { btn.style.background = ''; btn.disabled = false; }
    if (span) span.textContent = 'Gửi Đơn Đăng Ký';
    closeRegisterModal();
  }, 2500);
}


// ── TikTok Live Indicator (Vietnam time UTC+7) ───────────────────────────
function updateTikTokLiveStatus() {
  const card  = document.getElementById('tiktok-stat-card');
  const label = document.getElementById('tiktok-live-label');
  if (!card || !label) return;

  // Vietnam time = UTC+7
  const now = new Date();
  const vnH = (now.getUTCHours() + 7) % 24;
  const vnM = now.getUTCMinutes();
  const totalMin = vnH * 60 + vnM;

  // Live windows: 12:00–13:00 and 21:00–22:00
  const isLive = (totalMin >= 720 && totalMin < 780) ||   // 12h00 → 13h00
                 (totalMin >= 1260 && totalMin < 1320);    // 21h00 → 22h00

  if (isLive) {
    card.classList.add('on-air');
    label.textContent = 'LIVE';
    label.setAttribute('data-vi', 'LIVE');
    label.setAttribute('data-en', 'LIVE');
  } else {
    card.classList.remove('on-air');
    label.textContent = 'Soon';
    label.setAttribute('data-vi', 'Soon');
    label.setAttribute('data-en', 'Soon');
  }
}
updateTikTokLiveStatus();
setInterval(updateTikTokLiveStatus, 60000); // check every minute


// ── Gauge animation helpers ──────────────────────────────────────────
let fgFirstLoad = true;

function animateScoreCount(target) {
  const el = document.getElementById('fgScore');
  if (!el) return;
  const start = performance.now();
  const duration = 950;
  (function tick(now) {
    const t = Math.min((now - start) / duration, 1);
    const eased = 1 - Math.pow(1 - t, 3);
    el.textContent = Math.round(target * eased);
    if (t < 1) requestAnimationFrame(tick);
  })(performance.now());
}

function elasticOut(t) {
  if (t <= 0) return 0;
  if (t >= 1) return 1;
  return Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * (2 * Math.PI / 3)) + 1;
}

function animateNeedleSweep(toAngle) {
  const el = document.getElementById('gaugeNeedle');
  if (!el) return;
  const fromAngle = -90;
  const start = performance.now();
  const duration = 1300;
  (function tick(now) {
    const t = Math.min((now - start) / duration, 1);
    const angle = fromAngle + (toAngle - fromAngle) * elasticOut(t);
    el.setAttribute('transform', `rotate(${angle.toFixed(1)}, 100, 100)`);
    if (t < 1) requestAnimationFrame(tick);
  })(performance.now());
}
