async function loadMarketSentiment() {
  try {
    // Fear & Greed from alternative.me
    const fgRes = await fetch('https://api.alternative.me/fng/?limit=1');
    const fgData = await fgRes.json();
    const score = parseInt(fgData.data[0].value);
    const classification = fgData.data[0].value_classification;

    const label = document.getElementById('fgLabel');
    label.textContent = classification;

    // Colour based on score
    let color = score < 25 ? '#F87171' : score < 45 ? '#F59E0B' : score < 55 ? '#FBBF24' : score < 75 ? '#86EFAC' : '#34D399';
    label.style.color = color;

    // ── Needle animation ──
    const pct = score / 100;
    const angle = -90 + pct * 180;
    if (fgFirstLoad) {
      animateNeedleSweep(angle);
      fgFirstLoad = false;
    } else {
      const needleEl = document.getElementById('gaugeNeedle');
      if (needleEl) needleEl.setAttribute('transform', `rotate(${angle}, 100, 100)`);
    }

    // Needle tip colour
    const tipEl = document.getElementById('needleTip');
    if (tipEl) tipEl.setAttribute('fill', color);

    // ── Segmented arc activation (staggered, CSS drop-shadow glow) ──
    const ARC_SEG_LEN = 51;
    const segGlowColors = ['', '#EF4444', '#F97316', '#FBBF24', '#86EFAC', '#34D399'];
    for (let i = 1; i <= 5; i++) {
      const seg = document.getElementById(`gauge-seg-${i}`);
      if (!seg) continue;
      const segStart = (i - 1) * 20;
      const segEnd   = i * 20;
      seg.classList.remove('gauge-seg-active');
      if (score >= segEnd) {
        // Fully active — staggered fade-in with CSS glow
        setTimeout(() => {
          seg.setAttribute('stroke-dashoffset', '0');
          seg.setAttribute('opacity', '0.92');
          seg.style.filter = `drop-shadow(0 0 8px ${segGlowColors[i]})`;
          seg.classList.add('gauge-seg-active');
        }, 180 + (i - 1) * 110);
      } else if (score > segStart) {
        // Partial fill with CSS glow
        const fraction   = (score - segStart) / 20;
        const dashOffset = (ARC_SEG_LEN * (1 - fraction)).toFixed(1);
        setTimeout(() => {
          seg.setAttribute('stroke-dashoffset', dashOffset);
          seg.setAttribute('opacity', '0.88');
          seg.style.filter = `drop-shadow(0 0 6px ${segGlowColors[i]})`;
        }, 180 + (i - 1) * 110);
      } else {
        // Inactive — no opacity, no filter
        seg.setAttribute('opacity', '0');
        seg.style.filter = 'none';
      }
    }

    // ── Ambient glow + card zone ──
    const glowEl = document.getElementById('fgAmbientGlow');
    if (glowEl) glowEl.style.background = color;
    const fgCard = document.querySelector('.hero-fg-card');
    if (fgCard) fgCard.dataset.zone = score < 40 ? 'fear' : score > 60 ? 'greed' : 'neutral';

    // ── Score count-up ──
    animateScoreCount(score);
    const scoreEl = document.getElementById('fgScore');
    if (scoreEl) {
      scoreEl.style.color = color;
      scoreEl.classList.add('score-glowing');
    }


    // BTC Dominance from CoinGecko global
    const cgRes = await fetch('https://api.coingecko.com/api/v3/global');
    const cgData = await cgRes.json();
    const btcPct = cgData.data.market_cap_percentage.btc.toFixed(1);
    const ethPct = cgData.data.market_cap_percentage.eth.toFixed(1);

    document.getElementById('btcDom').textContent = btcPct + '%';
    document.getElementById('ethDom').textContent = ethPct + '%';
    document.getElementById('btcDomBar').style.width = Math.min(btcPct, 100) + '%';
    document.getElementById('ethDomBar').style.width = Math.min(ethPct * 2.5, 100) + '%'; // scale eth for visual

    const now = new Date();
    document.getElementById('sentimentUpdated').textContent = 'Cập nhật: ' + now.toLocaleTimeString('vi-VN');
  } catch(e) {
    document.getElementById('fgScore').textContent = '--';
    document.getElementById('fgLabel').textContent = 'Không tải được';
    console.log('Market sentiment error:', e);
  }
}
